cat > /tmp/test_segment_match_type.go << 'EOF'
package main

import (
	"context"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/common"
	"go.flipt.io/flipt/internal/server/evaluation"
	"go.flipt.io/flipt/internal/storage"
	"go.flipt.io/flipt/rpc/flipt"
	rpcevaluation "go.flipt.io/flipt/rpc/flipt/evaluation"
	"go.uber.org/zap/zaptest"
)

func TestSegmentMatchType(t *testing.T) {
	var (
		flagKey      = "test-flag"
		namespaceKey = "test-namespace"
		store        = &common.StoreMock{}
		logger       = zaptest.NewLogger(t)
		s            = evaluation.New(logger, store)
		flag         = &flipt.Flag{
			NamespaceKey: namespaceKey,
			Key:          flagKey,
			Enabled:      true,
			Type:         flipt.FlagType_VARIANT_FLAG_TYPE,
		}
	)

	store.On("GetFlag", context.TODO(), storage.NewResource(namespaceKey, flagKey)).Return(flag, nil)

	// Test with OR_SEGMENT_OPERATOR
	store.On("GetEvaluationRules", context.TODO(), storage.NewResource(namespaceKey, flagKey)).Return(
		[]*storage.EvaluationRule{
			{
				ID:               "1",
				FlagKey:          flagKey,
				Rank:             0,
				SegmentOperator:  flipt.SegmentOperator_OR_SEGMENT_OPERATOR,
				Segments: map[string]*storage.EvaluationSegment{
					"bar": {
						SegmentKey: "bar",
						MatchType:  flipt.MatchType_ALL_MATCH_TYPE,
						Constraints: []storage.EvaluationConstraint{
							{
								ID:       "2",
								Type:     flipt.ComparisonType_STRING_COMPARISON_TYPE,
								Property: "hello",
								Operator: flipt.OpEQ,
								Value:    "world",
							},
						},
					},
				},
			},
		}, nil)

	store.On("GetEvaluationDistributions", context.TODO(), storage.NewID("1")).Return([]*storage.EvaluationDistribution{}, nil)

	res, err := s.Variant(context.Background(), &rpcevaluation.EvaluationRequest{
		FlagKey:      flagKey,
		EntityId:     "test-entity",
		NamespaceKey: namespaceKey,
		Context: map[string]string{
			"hello": "world",
		},
	})

	require.NoError(t, err)
	assert.Equal(t, true, res.Match)
	assert.Equal(t, "ANY", res.SegmentMatchType)
	t.Logf("Result: %+v", res)
}
EOF
