go run -eval 'package main; import ("fmt"; "go.flipt.io/flipt/rpc/flipt/evaluation"); func main() { v := &evaluation.VariantEvaluationResponse{SegmentMatchType: "ANY"}; fmt.Printf("SegmentMatchType: %s\n", v.SegmentMatchType); fmt.Printf("GetSegmentMatchType: %s\n", v.GetSegmentMatchType()) }' 2>&1 || (cat << 'EOF' > /tmp/verify.go
